Here are the public test cases for feature1_1_message_json_encode:
{
  "description": "Encode an application message containing scalar fields, an enum-like value, and a nested address into compact JSON text.",
  "cases": [
    {
      "input": {
        "operation": "message_json_encode",
        "person": {
          "firstName": "Bob",
          "lastName": "Stone",
          "age": 30,
          "gender": "Male",
          "address": {
            "unit": 12,
            "street": "Prince St",
            "zipCode": "00001"
          }
        }
      },
      "expected_output": "json={\"FirstName\":\"Bob\",\"LastName\":\"Stone\",\"Age\":30,\"Gender\":\"Male\",\"Address\":{\"Unit\":12,\"Street\":\"Prince St\",\"ZipCode\":\"00001\"}}\n"
    }
  ]
}

